                                <clipPath id="clip0_81_26">
                                <rect width="16" height="12.8"/>
                                </clipPath>
                                </defs>
                            </svg>
                        </span>
                        Шуурхай
                    </button>
                </div>
                </div>

                <!-- Tracking code section -->
                <div class="tracking-section">
                <h3>Трак Код*</h3>
                <div class="input-field">
                    <input type="text" placeholder="трак кодоо энд бичих эсвэл хуулж тавь" v-model="form.trackingNumber" />
                </div>
                </div>

                <!-- Submit button -->
                <button class="submit-btn" type="submit" @click="handleAddTrack">Нэмэх</button>
            </form>
            </div>
        </div>

        <div class="cargos">
            <h3 class="total-price">Нийт: <span>{{numberWithCommas(totalPrice)}} ₮</span></h3>
            <!-- New Filter Buttons Section -->
            <h3 class="title">Төлөв:</h3>
            <div class="filter-buttons">
                <button 
                    @click="activeFilter = null" 
                    :class="activeFilter === null ? 'active-filter' : ''"
                    class="filter-button"
                >
                    Бүгд
                </button>
                <button 
                    @click="activeFilter = 'DELIVERED_TO_UB'" 
                    :class="activeFilter === 'DELIVERED_TO_UB' ? 'active-filter' : ''"
                    class="filter-button"
                >
                    Улаанбаатар-д ирсэн
                </button>
                <button 
                    @click="activeFilter = 'IN_TRANSIT'" 
                    :class="activeFilter === 'IN_TRANSIT' ? 'active-filter' : ''"
                    class="filter-button"
                >
                    Эрээн-с гарсан
                </button>
                <button 
                    @click="activeFilter = 'RECEIVED_AT_ERENHOT'" 
                    :class="activeFilter === 'RECEIVED_AT_ERENHOT' ? 'active-filter' : ''"
                    class="filter-button"
                >
                    Эрээн-д ирсэн
                </button>
                <button 
                    @click="activeFilter = 'PRE_REGISTERED'" 
                    :class="activeFilter === 'PRE_REGISTERED' ? 'active-filter' : ''"
                    class="filter-button"
                >
                    Урьдчилан бүртгүүлсэн
                </button>
                <button 
                    @click="activeFilter = 'DELIVERED'" 
                    :class="activeFilter === 'DELIVERED' ? 'active-filter' : ''"
                    class="filter-button"
                >
                    Бараа хүлээлгэн өгсөн
                </button>
            </div>

            <div v-if="loading">Loading...</div>
            <div v-else-if="error" class="error">
            {{ error }}
            </div>
            <div v-else>
                <div v-if="filteredAndSortedCargos.length === 0">
                    <p>Ачаа олдсонгүй.</p>
                </div>
                <div v-else>
                    <h4 class="title">Тракууд</h4>
                    <div v-for="cargo in filteredAndSortedCargos" :key="cargo.id" class="cargo-item">
                        <a :href="`/track/${cargo.trackingNumber}`">
                            <div class="cargo-lnk">
                                <div class="ttl">
                                    <p class="id">{{ cargo.nickname ? cargo.nickname : cargo.trackingNumber }}</p>
                                    <div class="stat" :class="cargo.currentStatus=='DELIVERED_TO_UB' && 'highlight'"> {{ currentStatus(cargo.currentStatus) }}</div>
                                </div>
                                <div class="price" v-if="cargo.currentStatus=='DELIVERED_TO_UB' && cargo.price"><p>Төлбөр:</p><p>{{ numberWithCommas(cargo.price) }}₮</p></div>
                            </div>
                        </a>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script setup>
import { ref, computed, onMounted } from 'vue';
import { useRouter } from 'vue-router';

const router = useRouter()

useHead({
    titleTemplate: '%s | home'
})

const form = ref({
    nickname: '',
    cargoType: 'NORMAL',
    trackingNumber: ''
})

// Add activeFilter ref for tracking the selected filter
const activeFilter = ref(null);

function currentStatus(status){
  switch (status) {
    case 'PRE_REGISTERED':
      return 'Урьдчилан бүртгүүлсэн'
      break;
    case 'RECEIVED_AT_ERENHOT':
      return 'Эрээн-д ирсэн'
      break;
    case 'IN_TRANSIT':
      return 'Эрээн-с гарсан'
      break;
    case 'DELIVERED_TO_UB':
      return 'Улаанбаатар-д ирсэн'
      break;
    case 'DELIVERED':
      return 'Бараа хүлээлгэн өгсөн'
      break;
  }
}

const totalPrice = ref(0)

// Reference to the input element
const trackInput = ref(null)
const trackCode = ref('')
const token = ref('')

const addTrackModal = ref(false)

function numberWithCommas(x) {
    return x.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

const addTrackModalToggle=()=>{
    addTrackModal.value = !addTrackModal.value;
}

// Handle paste event
const handlePaste = (event) => {
    event.preventDefault()
    const text = event.clipboardData.getData('text')
    trackCode.value = text.trim()
}

// Handle paste button click
const handlePasteFromClipboard = async () => {
    try {
        const text = await navigator.clipboard.readText()
        trackCode.value = text.trim()
    } catch (err) {
        console.error('Failed to read clipboard:', err)
    }
}

// Handle check button click
const handleCheck = async() => {
    router.push(`/track/${trackCode.value}`)
}

onMounted(async () => {
    token.value = localStorage.getItem('authToken') || '';
})

// Reactive state
const cargoTrackings = ref([]);
const loading = ref(true);
const error = ref(null);

// New computed property for filtered and sorted cargos
const filteredAndSortedCargos = computed(() => {
    // First filter by the active filter if one is selected
    let result = activeFilter.value 
        ? cargoTrackings.value.filter(cargo => cargo.currentStatus === activeFilter.value)
        : [...cargoTrackings.value];
    
    // Then sort according to the specified order
    const statusPriority = {
        'DELIVERED_TO_UB': 1,
        'IN_TRANSIT': 2,
        'RECEIVED_AT_ERENHOT': 3,
        'PRE_REGISTERED': 4,
        'DELIVERED': 5
    };
    
    return result.sort((a, b) => {
        return statusPriority[a.currentStatus] - statusPriority[b.currentStatus];
    });
});

const handleAddTrack = async() => {
    const token = localStorage.getItem('authToken');
    if (!token) {
      throw new Error('No authentication token found. Please log in.');
    }

    try {
        const response = await fetch('/api/createCargo', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                Authorization: `Bearer ${token}`,
            },
            body: JSON.stringify({
                nickname: form.value.nickname,
                cargoType: form.value.cargoType,
                trackingNumber: form.value.trackingNumber
            }),
        })

        if (!response.ok) {
            const error = await response.json()
            alert(error.message)
            return
        }

        const data = response.json()

        if (data.statusCode === 406) {
            alert(data.message)
            return
        }

        addTrackModal.value = false
        alert('Амжилттай нэмэгдлээ!')
        fetchCargoTrackingData();
        form.value.nickname = ''
        form.value.cargoType = 'NORMAL'
        form.value.trackingNumber = ''

    } catch (err) {
        console.error('Бүртгэл амжилтгүй:', err)
        alert(err.message)
        
    } finally {
        loading.value = false
    }
}

// Function to format dates
const formatDate = (dateString) => {
  if (!dateString) return 'N/A';
  return new Date(dateString).toLocaleString();
};

// Fetch cargo tracking data
const fetchCargoTrackingData = async () => {
  try {
    // Get the JWT token from localStorage (or cookies)
    const token = localStorage.getItem('authToken');
    if (!token) {
      throw new Error('No authentication token found. Please log in.');
    }

    // Fetch data from the API
    const response = await fetch('/api/cargoTrackData', {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    });

    if (!response.ok) {
      throw new Error(`Failed to fetch data: ${response.statusText}`);
    }

    const data = await response.json();
    cargoTrackings.value = data.body || [];
    
    // Reset totalPrice before recalculating
    totalPrice.value = 0;
    
    if(cargoTrackings.value.length > 0){
        for(const cargo of cargoTrackings.value){
            if(cargo.price && cargo.currentStatus == 'DELIVERED_TO_UB'){
                totalPrice.value = totalPrice.value + parseInt(cargo.price)
            }
        }
    }
  } catch (err) {
    error.value = err.message;
    console.error('Error fetching cargo tracking data:', err);
  } finally {
    loading.value = false;
  }
};

// Fetch data when the component is mounted
onMounted(() => {
  fetchCargoTrackingData();
});
</script>

<style lang="scss" scoped>
@use "./index.scss";
</style>